msg.payload = crypto.randomUUID();
global.set("uuid",msg.payload)
return msg;

const cfg = msg.payload;
const errors   = [];
const warnings = [];
const infos    = [];

// ─── Helpers ────────────────────────────────────────────────────────────────

const isString  = v => typeof v === 'string' && v.trim().length > 0;
const isNumber  = v => typeof v === 'number';
const isBool    = v => typeof v === 'boolean';
const isArray   = v => Array.isArray(v);
const isObject  = v => v !== null && typeof v === 'object' && !Array.isArray(v);

const BROKER_PROTOCOLS = /^(mqtt|mqtts|ws|wss):\/\/.+/;
const URL_RE           = /^https?:\/\/.+/;
const S3_URL_RE        = /^https?:\/\/[^:\/]+(:\d+)?$/;

const isValidMqttTopic = (t, path) => {
    if (typeof t !== 'string' || t.length === 0) return 'empty or not a string';
    const parts = t.split('/');
    if (parts.length < 1) return 'empty topic';

    // Helper: valid intermediate segment — alphanumeric + single hyphens (no leading/trailing/double), no underscore, no dot
    const isValidSegment = s => /^[a-z0-9]+(-[a-z0-9]+)*$/.test(s);

    for (let i = 0; i < parts.length; i++) {
        const part = parts[i];
        const isLast = i === parts.length - 1;

        if (part === '#') {
            if (!isLast) return `'#' at level ${i+1} must be the last level`;
            continue;
        }

        switch (i) {
            case 0: // first level: origin, cache, monitor or +
                if (!['origin','cache','monitor','+'].includes(part))
                    return `level 1 must be 'origin', 'cache', 'monitor' or '+' (got '${part}')`;
                break;
            case 1: // second level: must be 'a', no +
                if (part !== 'a')
                    return `level 2 must be 'a' (got '${part}')${part === '+' ? ' — + not allowed here' : ''}`;
                break;
            case 2: // third level: must be 'wis2', no +
                if (part !== 'wis2')
                    return `level 3 must be 'wis2' (got '${part}')${part === '+' ? ' — + not allowed here' : ''}`;
                break;
            case 3: // fourth level: must contain at least one '-', or be +
                if (part === '+') break;
                if (!isValidSegment(part) || !part.includes('-'))
                    return `level 4 must contain at least one '-' and be alphanumeric-hyphen (got '${part}')`;
                break;
            case 4: // fifth level: data, metadata or +
                if (!['data','metadata','+'].includes(part))
                    return `level 5 must be 'data', 'metadata' or '+' (got '${part}')`;
                break;
            default: // deeper levels: valid segment or +, last may be # (handled above)
                if (part === '+') break;
                if (isLast) {
                    if (!/^[a-z]+$/.test(part))
                        return `last level must be lowercase a-z only (got '${part}')`;
                } else {
                    if (!isValidSegment(part))
                        return `level ${i+1} '${part}' is invalid — use lowercase alphanumeric with single hyphens only`;
                }
        }
    }
    return null; // null = valid
};

const checkBroker = (broker, path) => {
    if (!isString(broker.broker))           errors.push(`${path}.broker: missing or empty`);
    else if (!BROKER_PROTOCOLS.test(broker.broker))
                                            errors.push(`${path}.broker: invalid protocol (${broker.broker}) — must be mqtt/mqtts/ws/wss`);
    if (!isString(broker.username))         warnings.push(`${path}.username: missing`);
    if (!isString(broker.password))         warnings.push(`${path}.password: missing`);
    if (broker.version !== undefined && ![3,4,5].includes(broker.version))
                                            errors.push(`${path}.version: must be 3, 4 or 5 (got ${broker.version})`);
    if (broker.verifycert !== undefined && !isBool(broker.verifycert))
                                            errors.push(`${path}.verifycert: must be boolean`);
};

// ─── Root ───────────────────────────────────────────────────────────────────

if (!isObject(cfg)) {
    errors.push('Configuration root is not a valid YAML object');
    msg.payload = { valid: false, errors, warnings, infos };
    return msg;
}

// Declare roles early so all sections can reference it
const roles = isObject(cfg.global) && typeof cfg.global.roles === 'string'
    ? cfg.global.roles.split(',').map(r => r.trim())
    : [];

// ─── global ─────────────────────────────────────────────────────────────────

const VALID_ROLES = ['SUBSCRIBER','DOWNLOADER','CLEANER','REPORTER','REPLAYER'];

if (!isObject(cfg.global)) {
    errors.push('global: section missing');
} else {
    const g = cfg.global;

    // roles
    if (!isString(g.roles)) {
        errors.push('global.roles: missing or empty');
    } else {
        const roles = g.roles.split(',').map(r => r.trim());
        const unknown = roles.filter(r => !VALID_ROLES.includes(r));
        if (unknown.length) errors.push(`global.roles: unknown role(s): ${unknown.join(', ')}`);
        infos.push(`global.roles: ${roles.join(', ')}`);

        // cross-check: required sections per role
        if (roles.includes('SUBSCRIBER')   && !isObject(cfg.subscriber))  errors.push('global.roles includes SUBSCRIBER but subscriber: section is missing');
        if (roles.includes('DOWNLOADER')   && !isObject(cfg.downloader))  errors.push('global.roles includes DOWNLOADER but downloader: section is missing');
        // cleaner section absence is handled in the cleaner validation block
        // reporter section is optional — no check needed
        if (roles.includes('REPLAYER')     && !isObject(cfg.replayer))    errors.push('global.roles includes REPLAYER but replayer: section is missing');
    }

    // worker
    if (!isString(g.worker))              errors.push('global.worker: missing or empty');

    // queue
    if (!isString(g.queue))               errors.push('global.queue: missing or empty');

    // log-level
    const VALID_LOG = ['info','warn','debug'];
    if (!isString(g['log-level']))        warnings.push('global.log-level: missing, will default to no logging');
    else if (!VALID_LOG.includes(g['log-level']))
                                          errors.push(`global.log-level: invalid value '${g['log-level']}' — must be info/warn/debug`);


    // test-mode-duration
    if (g['test-mode-duration'] !== undefined && !isNumber(g['test-mode-duration']))
                                          errors.push('global.test-mode-duration: must be a number');

    // global-cache
    if (g['global-cache'] !== undefined && !isBool(g['global-cache']))
                                          errors.push('global.global-cache: must be boolean');

    // localbroker
    if (!isArray(g.localbroker) || g.localbroker.length === 0) {
        warnings.push('global.localbroker: missing or empty — no local MQTT broker configured (PUB1/PUB2 will not connect)');
    } else {
        g.localbroker.forEach((b, i) => checkBroker(b, `global.localbroker[${i}]`));
        if (g.localbroker.length > 2) warnings.push('global.localbroker: more than 2 brokers defined — only PUB1 and PUB2 are wired in the flow');
    }
}

// ─── subscriber ─────────────────────────────────────────────────────────────

if (isObject(cfg.subscriber)) {
    const s = cfg.subscriber;

    // globalbroker
    if (!isArray(s.globalbroker) || s.globalbroker.length === 0) {
        errors.push('subscriber.globalbroker: missing or empty — nothing to subscribe to');
    } else {
        s.globalbroker.forEach((b, i) => checkBroker(b, `subscriber.globalbroker[${i}]`));
        if (s.globalbroker.length > 2) warnings.push('subscriber.globalbroker: more than 2 brokers defined — only GB1 and GB2 are wired in the flow');
    }

    // priority-global-cache
    if (s['priority-global-cache'] !== undefined) {
        if (!isArray(s['priority-global-cache'])) errors.push('subscriber.priority-global-cache: must be an array');
        else if (s['priority-global-cache'].some(v => !isString(v)))
            errors.push('subscriber.priority-global-cache: all entries must be strings');
    }

    // mqtt
    if (!isObject(s.mqtt)) {
        errors.push('subscriber.mqtt: section missing');
    } else {
        const m = s.mqtt;

        // whitelist — required, must be non-empty array of valid MQTT topics
        if (!isArray(m.whitelist) || m.whitelist.length === 0)
            errors.push('subscriber.mqtt.whitelist: missing or empty — nothing will be subscribed');
        else {
            m.whitelist.forEach((t, i) => {
                if (!isString(t))              errors.push(`subscriber.mqtt.whitelist[${i}]: must be a string`);
                else { const err = isValidMqttTopic(t); if (err) errors.push(`subscriber.mqtt.whitelist[${i}]: '${t}' — ${err}`); }
            });
            infos.push(`subscriber.mqtt.whitelist: ${m.whitelist.length} topic(s)`);
        }

        // blacklist — optional, but if present must be array of valid MQTT topics
        if (m.blacklist !== undefined) {
            if (!isArray(m.blacklist)) errors.push('subscriber.mqtt.blacklist: must be an array');
            else {
                m.blacklist.forEach((t, i) => {
                    if (!isString(t))              errors.push(`subscriber.mqtt.blacklist[${i}]: must be a string`);
                    else if (!/^[a-zA-Z0-9\-\/\+#]+$/.test(t)) errors.push(`subscriber.mqtt.blacklist[${i}]: '${t}' — only alphanumeric, -, +, # and / allowed`);
                });
                infos.push(`subscriber.mqtt.blacklist: ${m.blacklist.length} topic(s)`);
            }
        }

        // global-replay
        if (m['global-replay'] !== undefined && m['global-replay'] !== null) {
            if (!isString(m['global-replay'])) errors.push('subscriber.mqtt.global-replay: must be a string or null');
            else infos.push(`subscriber.mqtt.global-replay: ${m['global-replay']}`);
        }
    }
}

// ─── downloader ─────────────────────────────────────────────────────────────

if (isObject(cfg.downloader)) {
    const d = cfg.downloader;

    if (!isString(d['aria-secret']))       errors.push('downloader.aria-secret: missing or empty — required');
    if (!isString(d['aria-url']))          errors.push('downloader.aria-url: missing or empty');
    else if (!d['aria-url'].startsWith('ws://') && !d['aria-url'].startsWith('wss://'))
                                           errors.push(`downloader.aria-url: must start with ws:// or wss:// (got ${d['aria-url']})`);
    if (!isNumber(d['aria-inqueue']))       errors.push('downloader.aria-inqueue: missing or not a number — must be a positive integer');
    else if (d['aria-inqueue'] <= 0)        errors.push('downloader.aria-inqueue: must be greater than 0');
    if (!isString(d['cache-name']))         warnings.push('downloader.cache-name: missing');
    if (!isString(d['download-url']))      errors.push('downloader.download-url: missing or empty');
    else if (!URL_RE.test(d['download-url']))
                                           errors.push(`downloader.download-url: invalid URL (${d['download-url']})`);

    // rename-to-xxx flags: xxx must be one of date, topic, s3
    const VALID_RENAME = ['date', 'topic', 's3'];
    const renameKeys = Object.keys(d).filter(k => k.startsWith('rename-to-'));
    renameKeys.forEach(k => {
        const suffix = k.replace('rename-to-', '');
        if (!VALID_RENAME.includes(suffix))
            errors.push(`downloader.${k}: invalid suffix '${suffix}' — must be one of: ${VALID_RENAME.join(', ')}`);
        if (!isBool(d[k]))
            errors.push(`downloader.${k}: must be boolean`);
    });

    const renameDate  = d['rename-to-date']  === true;
    const renameTopic = d['rename-to-topic'] === true;
    const renameS3    = d['rename-to-s3']    === true;
    const renameCount = [renameDate, renameTopic, renameS3].filter(Boolean).length;
    if (renameCount > 1) errors.push('downloader: only one of rename-to-date / rename-to-topic / rename-to-s3 can be true at a time');
    else if (renameCount === 1) infos.push(`downloader.rename-to: ${renameDate ? 'date' : renameTopic ? 'topic' : 's3'}`);

    // s3access — required only if rename-to-s3 is true
    if (renameS3) {
        if (!isObject(d.s3access)) {
            errors.push('downloader.s3access: required when rename-to-s3 is true but section is missing');
        } else {
            const s3 = d.s3access;
            if (!isString(s3.url))         errors.push('downloader.s3access.url: missing or empty');
            else if (!S3_URL_RE.test(s3.url))
                                           errors.push(`downloader.s3access.url: invalid format (${s3.url}) — expected http(s)://host:port`);
            if (!isString(s3.accesskey))   errors.push('downloader.s3access.accesskey: missing or empty');
            if (!isString(s3.secretkey))   errors.push('downloader.s3access.secretkey: missing or empty');
            if (!isString(s3.bucket))      errors.push('downloader.s3access.bucket: missing or empty');
            if (!isString(s3.region))      warnings.push('downloader.s3access.region: missing — minio may use a default');
        }
    } else if (isObject(d.s3access)) {
        warnings.push('downloader.s3access: defined but rename-to-s3 is not true — section will be ignored');
    }
}

// ─── cleaner ─────────────────────────────────────────────────────────────────

if (roles.includes('CLEANER')) {
    if (!isObject(cfg.cleaner)) {
        warnings.push('cleaner: section missing — files will never be cleaned from cache; consider using rename-to-s3 in the downloader section instead');
    } else {
        const c = cfg.cleaner;
        if (c['keep-in-cache'] === undefined)
            errors.push('cleaner.keep-in-cache: mandatory when cleaner section is present');
        else if (!isNumber(c['keep-in-cache']))
            errors.push('cleaner.keep-in-cache: must be a number (seconds)');
        else if (c['keep-in-cache'] <= 0)
            warnings.push('cleaner.keep-in-cache: value is <= 0 — files will be deleted immediately');
    }
}

// ─── replayer ────────────────────────────────────────────────────────────────

if (isObject(cfg.replayer)) {
    const r = cfg.replayer;
    if (!isString(r['global-replay-url']))  errors.push('replayer.global-replay-url: missing or empty');
    else if (!URL_RE.test(r['global-replay-url']))
                                            errors.push(`replayer.global-replay-url: invalid URL (${r['global-replay-url']})`);
}

// ─── cross-check: global-replay requires REPLAYER role ───────────────────────

if (isObject(cfg.subscriber) && isObject(cfg.subscriber.mqtt)) {
    const gr = cfg.subscriber.mqtt['global-replay'];
    if (gr && gr !== 'null' && !roles.includes('REPLAYER'))
        warnings.push('subscriber.mqtt.global-replay is set but REPLAYER is not in global.roles');
}

// ─── Unknown / unused fields ─────────────────────────────────────────────────

// Fields actually consumed by the flow (from analysis of all change/switch/function nodes)
const KNOWN_GLOBAL = ['roles','worker','queue','log-level','global-cache','test-mode-duration','localbroker'];
const KNOWN_SUBSCRIBER = ['globalbroker','priority-global-cache','mqtt'];
const KNOWN_SUBSCRIBER_MQTT = ['whitelist','blacklist','global-replay'];
const KNOWN_DOWNLOADER = ['aria-secret','aria-url','aria-inqueue','cache-name','download-url','rename-to-date','rename-to-topic','rename-to-s3','s3access'];
const KNOWN_S3ACCESS = ['url','accesskey','secretkey','bucket','region'];
const KNOWN_CLEANER = ['keep-in-cache'];
const KNOWN_REPLAYER = ['global-replay-url'];
const KNOWN_REPORTER = [];

const checkUnknown = (obj, known, path) => {
    if (!isObject(obj)) return;
    Object.keys(obj).forEach(k => {
        if (!known.includes(k))
            warnings.push(`${path}.${k}: present in config but not used by the flow`);
    });
};

checkUnknown(cfg.global,     KNOWN_GLOBAL,      'global');
checkUnknown(cfg.subscriber, KNOWN_SUBSCRIBER,   'subscriber');
if (isObject(cfg.subscriber && cfg.subscriber.mqtt))
    checkUnknown(cfg.subscriber.mqtt, KNOWN_SUBSCRIBER_MQTT, 'subscriber.mqtt');
checkUnknown(cfg.downloader, KNOWN_DOWNLOADER,   'downloader');
if (isObject(cfg.downloader) && isObject(cfg.downloader.s3access))
    checkUnknown(cfg.downloader.s3access, KNOWN_S3ACCESS, 'downloader.s3access');
checkUnknown(cfg.cleaner,    KNOWN_CLEANER,      'cleaner');
checkUnknown(cfg.replayer,   KNOWN_REPLAYER,     'replayer');
// reporter section intentionally has no required fields

// Top-level unknown sections
const KNOWN_SECTIONS = ['global','subscriber','downloader','cleaner','replayer','reporter'];
if (isObject(cfg)) {
    Object.keys(cfg).forEach(k => {
        if (!KNOWN_SECTIONS.includes(k))
            warnings.push(`${k}: unknown top-level section — not used by the flow`);
    });
}

// ─── Result ──────────────────────────────────────────────────────────────────

const valid = errors.length === 0;

msg.payload = { valid, errors, warnings, infos };
msg.topic   = valid ? 'CONFIG_VALID' : 'CONFIG_INVALID';

return msg;

const geojson = msg.payload;

// Separate links into priority (canonical/update) and others
const priorityLinks = [];
const otherLinks = [];

geojson.links.forEach(link => {
    if (link.rel === 'canonical' || link.rel === 'update') {
        priorityLinks.push(link);
    } else {
        otherLinks.push(link);
    }
});

// Reconstruct links array with priority links first
geojson.links = [...priorityLinks, ...otherLinks];

msg.payload = geojson;

// Create array for 9 outputs (all null initially)
const outputs = [null, null, null, null, null, null, null, null, null];

// Check if topic contains origin/a/wis2
if (msg.topic && msg.topic.includes('origin/a/wis2')) {
    outputs[0] = msg;  // Send to output 1
    return outputs;
}

// Check if topic contains cache/a/wis2
if (msg.topic && msg.topic.includes('cache/a/wis2')) {
    // Get the global-cache array from global context
    const cacheArray = global.get('priority-global-cache');

    // If priority-global-cache doesn't exist, output on first output
    if (!cacheArray) {
        outputs[0] = msg;
        return outputs;
    }

    // Check if properties.global-cache exists
    const globalCache = msg.payload.properties['global-cache'];

    if (globalCache) {
        // Find position in array
        const position = cacheArray.indexOf(globalCache);

        // If found in array, send to corresponding output (position + 2)
        if (position !== -1 && position < 8) {  // Max 8 positions (outputs 2-9)
            outputs[position + 1] = msg;  // position 0 -> output 2 (index 1)
        }
        // If not found or position >= 8, all outputs remain null (nothing sent)
    }
    // If no globalCache, all outputs remain null (nothing sent)

    return outputs;
}

// If topic doesn't match either pattern, send nothing
return outputs;

let topic = msg.topic;
const blacklist = global.get('blacklist');

// If topic starts with replay/a/wis2/, remove first 4 levels
if (topic.startsWith('replay/a/wis2/')) {
    const parts = topic.split('/');
    // Remove first 4 parts: replay, a, wis2, and the next item
    topic = parts.slice(5).join('/');
}

// If blacklist is false/null/undefined or empty array, allow all messages
if (!blacklist || blacklist.length === 0) {
    return msg;
}

function isBlacklisted(topic, pattern) {
    // Split both into parts
    const topicParts = topic.split('/');
    const patternParts = pattern.split('/');

    for (let i = 0; i < patternParts.length; i++) {
        const patternPart = patternParts[i];
        const topicPart = topicParts[i];

        if (patternPart === '#') {
            // # matches everything remaining - always true
            return true;
        }

        if (topicPart === undefined) {
            // Topic is shorter than pattern - no match
            return false;
        }

        if (patternPart === '+') {
            // + matches exactly one level - continue
            continue;
        }

        if (patternPart !== topicPart) {
            // Literal mismatch - no match
            return false;
        }
    }

    // Pattern exhausted - match only if topic is also exhausted
    return topicParts.length === patternParts.length;
}

// Check if topic matches any blacklist entry
const blocked = blacklist.some(pattern => isBlacklisted(topic, pattern));

// If blocked, return null (silently drop message)
// If not blocked, pass message through
return blocked ? null : msg;

