return blocked ? null : msg;

const input = msg.payload[0];  // Get the first element of the outer array
const queue = input[0];
const entries = input[1];

const messages = entries.map(entry => {
  const id = entry[0];
  const fields = entry[1];

  // Convert the flat array of key-value pairs to an object
  const obj = { id: id };
  for (let i = 0; i < fields.length; i += 2) {
    obj[fields[i]] = fields[i + 1];
  }

  return { downloads: obj };
