const method = msg.method;
const hashing = msg.hash;
const download = global.get("download-url");
const worker = global.get("worker");
const renameToDate = global.get("rename-to-date");
const renameToTopic = global.get("rename-to-topic");
const renameToS3 = global.get("rename-to-s3");

let filepath = msg.status.result.files[0].path;
try {
    msg.length = fs.statSync(filepath).size;
} catch (err) {
    msg.length = 0;
}

// Function to handle renaming logic
const handleRename = () => {
    let renamed = false;

    if (renameToDate && msg.wnmpubtime) {
        try {
            const baseDir = path.dirname(filepath);
            const filename = path.basename(filepath);

            const formatted = new Date(msg.wnmpubtime).toISOString().slice(0, 13).replace('T', '/').replace(/-/g, '/');
            const dateDir = path.join(baseDir, formatted);

            fs.mkdirSync(dateDir, { recursive: true });

            const newFilepath = path.join(dateDir, filename);

            if (fs.existsSync(newFilepath)) {
                msg.payload = "FAIL";
                fs.unlinkSync(filepath);
                return { renamed: false, failed: true };
            }

            fs.renameSync(filepath, newFilepath);
            filepath = newFilepath;
            renamed = true;
        } catch (err) {
            throw new Error("Failed to move file to date directory: " + err.message);
        }
